import { reactive } from 'vue'
import { useStore } from 'vuex'
import { user } from '@/api/user'
import { showToast } from '@/components/ToastMessage'
import { ElMessage } from 'element-plus'

export function useChangePassword() {
  const store = useStore()
  const state = reactive({
    oldPassword: '',
    newPassword: '',
    confirmPassword: '',
    loading: false,
    error: '',
    strength: 0
  })

  const checkPasswordStrength = (password) => {
    let score = 0

    if (password.length >= 6) score += 1
    if (password.length >= 10) score += 1

    if (/\d/.test(password)) score += 1

    if (/[a-z]/.test(password)) score += 1

    if (/[A-Z]/.test(password)) score += 1

    if (/[!@#$%^&*]/.test(password)) score += 1

    return score
  }

  const validatePassword = (password) => {
    if (!password) {
      return '密码不能为空'
    }
    if (password.length < 6 || password.length > 20) {
      return '密码长度必须在6-20个字符之间'
    }
    if (!/^(?=.*[A-Za-z])(?=.*\d)[A-Za-z\d]{6,20}$/.test(password)) {
      return '密码必须包含字母和数字'
    }
    if (/^\d+$/.test(password)) {
      return '密码不能是纯数字'
    }
    return ''
  }

  const updatePasswordStrength = (password) => {
    state.strength = checkPasswordStrength(password)
  }

  const handleUpdate = async () => {
    try {
      state.loading = true
      state.error = ''

      if (!state.oldPassword) {
        state.error = '请输入原密码'
        return false
      }

      const newPasswordError = validatePassword(state.newPassword)
      if (newPasswordError) {
        state.error = newPasswordError
        return false
      }

      if (state.newPassword !== state.confirmPassword) {
        state.error = '两次输入的密码不一致'
        return false
      }

      await user.updatePassword({
        old_password: state.oldPassword,
        new_password: state.newPassword,
        confirm_password: state.confirmPassword
      })

      ElMessage.success('密码修改成功')
      return true
    } catch (error) {
      state.error = error.response?.data?.message || '密码修改失败'
      return false
    } finally {
      state.loading = false
    }
  }

  return {
    state,
    handleUpdate,
    validatePassword,
    updatePasswordStrength
  }
}
